import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append('\n');
        }
        // Replace escaped newlines ("\\n") with spaces so they become token separators
        String all = raw.toString().replace("\\n", " ");
        String[] tokens = all.trim().split("\\s+");
        int idx = 0;
        if (tokens.length == 0) return;
        int T = Integer.parseInt(tokens[idx++]);
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int n = Integer.parseInt(tokens[idx++]);
            int m = Integer.parseInt(tokens[idx++]);
            int col = m - 1;
            long ans = 0;
            for (int i = 0; i < n; i++) {
                // read row
                int[] row = new int[m];
                for (int j = 0; j < m; j++) {
                    row[j] = Integer.parseInt(tokens[idx++]);
                }
                while (col >= 0 && row[col] < 0) {
                    col--;
                }
                ans += m - col - 1;
            }
            out.append(ans);
            if (tc < T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

